import{_ as n,c as a,a1 as h,o as c}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Trích xuất và Giải mã Hash SAM để Lấy Mật khẩu dạng Văn bản thuần","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/5-system-hacking/2-SAM-Hashes.md","filePath":"vi/categories/ethical-hacking-labs/5-system-hacking/2-SAM-Hashes.md"}'),i={name:"vi/categories/ethical-hacking-labs/5-system-hacking/2-SAM-Hashes.md"};function r(e,t,s,o,g,u){return c(),a("div",null,t[0]||(t[0]=[h('<h1 id="trich-xuat-va-giai-ma-hash-sam-đe-lay-mat-khau-dang-van-ban-thuan" tabindex="-1">Trích xuất và Giải mã Hash SAM để Lấy Mật khẩu dạng Văn bản thuần <a class="header-anchor" href="#trich-xuat-va-giai-ma-hash-sam-đe-lay-mat-khau-dang-van-ban-thuan" aria-label="Permalink to &quot;Trích xuất và Giải mã Hash SAM để Lấy Mật khẩu dạng Văn bản thuần&quot;">​</a></h1><p>Pwdump7 có thể được sử dụng để trích xuất các file được bảo vệ. Ophcrack là một chương trình miễn phí mã nguồn mở (GPL) giải mã mật khẩu Windows bằng cách sử dụng hash LM thông qua bảng rainbow.</p><p>SAM (Security Account Manager) là một file cơ sở dữ liệu có trong máy Windows lưu trữ tài khoản người dùng và mô tả bảo mật cho người dùng trên máy tính cục bộ. Nó lưu trữ mật khẩu người dùng ở dạng hash (hash LM và hash NTLM). Vì hàm hash là một chiều, điều này cung cấp một mức độ bảo mật nhất định cho việc lưu trữ mật khẩu.</p><p>Bạn cần có quyền quản trị viên để trích xuất nội dung của file SAM. Đánh giá độ mạnh mật khẩu là một cột mốc quan trọng trong quá trình đánh giá bảo mật của bạn. Bạn sẽ bắt đầu đánh giá mật khẩu bằng cách trích xuất đơn giản hash SAM và chạy nó với trình giải mã hash để phát hiện mật khẩu dạng văn bản thuần.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Sử dụng công cụ <strong>pwdump7</strong> để trích xuất hash mật khẩu.</li><li>Sử dụng công cụ Ophcrack để giải mã mật khẩu và thu được mật khẩu dạng văn bản thuần.</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Máy ảo Windows 10.</li></ul><h3 id="cong-cu" tabindex="-1">Công cụ <a class="header-anchor" href="#cong-cu" aria-label="Permalink to &quot;Công cụ&quot;">​</a></h3><ul><li><a href="https://ophcrack.sourceforge.io/" target="_blank" rel="noreferrer">Ophcrack</a></li><li><a href="https://www.tarasco.org/security/pwdump_7/index.html" target="_blank" rel="noreferrer">Pwdump7</a></li></ul><h2 id="tao-hash" tabindex="-1">Tạo Hash <a class="header-anchor" href="#tao-hash" aria-label="Permalink to &quot;Tạo Hash&quot;">​</a></h2><ol><li><p>Trước tiên, chúng ta cần tìm User ID liên kết với tên người dùng trên Windows 10.</p></li><li><p>Khởi chạy Command Prompt ở chế độ Administrator và nhập:</p></li></ol><p><code>wmic useraccount get name,sid &gt; c:/users.txt</code></p><p>Lệnh này sẽ lấy tên người dùng và User ID tương ứng. <strong>Ghi nhớ mỗi User ID cho các bước tiếp theo.</strong></p><ol start="3"><li>Để thu thập hash mật khẩu, truy cập thư mục <strong>pwdump7</strong> và chạy file .exe.</li></ol><p><code>cd C:\\Users\\Dummy\\Desktop\\pwdump7</code></p><p><code>PwDump7.exe</code></p><p>Để lưu thông tin này ra file .txt bên ngoài, nhập:</p><p><code>PwDump7.exe &gt; c:\\hashes.txt</code></p><p>Bây giờ đặt tên người dùng trước User ID tương ứng mà chúng ta đã thu thập ở <strong>bước 2</strong> và lưu file.</p><h2 id="su-dung-ophcrack-đe-giai-ma-hash" tabindex="-1">Sử dụng Ophcrack để giải mã hash <a class="header-anchor" href="#su-dung-ophcrack-đe-giai-ma-hash" aria-label="Permalink to &quot;Sử dụng Ophcrack để giải mã hash&quot;">​</a></h2><ol><li>Khởi chạy ứng dụng Ophcrack.</li><li>Nhấp vào <strong>Load</strong> và chọn <strong>PWDUMP file</strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/51d83f1edc90c3f3de3890d72f3a27552a2646b1/ophcrack.png" alt="Ophcrack" title="Ophcrack"></p><ol start="3"><li><p>Tiếp theo, bạn cần <a href="https://ophcrack.sourceforge.io/tables.php" target="_blank" rel="noreferrer">tải xuống</a> bảng để thực hiện giải mã. Chọn <strong>Vista free</strong> để tải xuống.</p></li><li><p>Truy cập Ophcrack và nhấp vào menu <strong>Tables</strong> để tải bảng.</p></li><li><p>Trong cửa sổ Table Selection, chọn <strong>Vista free</strong>, và nhấp <strong>Ok</strong>.</p></li></ol><p>Bảng table_vista_free này là một bảng được tính toán trước để đảo ngược hàm băm mật mã và khôi phục mật khẩu văn bản thuần đến một độ dài nhất định. Bảng <strong>table_vista_free</strong> được chọn được cài đặt dưới tên <strong>Vista free</strong>, được biểu thị bằng dấu chấm màu <strong>xanh lá</strong>.</p><ol start="6"><li>Nhấp <strong>Crack</strong> trên thanh menu. Ophcrack bắt đầu giải mã mật khẩu. Thao tác này sẽ mất vài phút.</li></ol>',26)]))}const p=n(i,[["render",r]]);export{m as __pageData,p as default};
